"use client";

import { useEffect } from "react";

/**
 * Client-side redirect so the browser receives the response (and any Set-Cookie
 * from middleware) before navigating. Server-side redirect() can drop those
 * headers and cause a redirect loop when GET /admin has no session.
 */
export default function RedirectToAdmin({ locale }: { locale: string }) {
  useEffect(() => {
    const segment = locale || "en";
    window.location.replace(`${window.location.origin}/${segment}/admin`);
  }, [locale]);
  return null;
}
